import { MakeLogicType, actions, afterMount, connect, kea, listeners, path, reducers, selectors } from 'kea'
import { loaders } from 'kea-loaders'

import { lemonToast } from '@posthog/lemon-ui'

import { teamLogic } from 'scenes/teamLogic'

import { DEFAULT_APPEARANCE, THEME_PALETTES, ThemePreset } from './constants'
import { cookieBannerCreate, cookieBannerList, cookieBannerPartialUpdate } from './generated/api'
import type { CookieBannerAppearanceApi, CookieBannerConfigApi } from './generated/api.schemas'

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface cookieBannerLogicValues {
    currentTeamId: number | null // teamLogic
    activeTheme: ThemePreset | null
    appearanceDraft: CookieBannerAppearanceApi
    config: CookieBannerConfigApi | null
    configLoading: boolean
    effectiveAppearance: Required<CookieBannerAppearanceApi>
    enabledDraft: boolean
    isDirty: boolean
    saving: boolean
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface cookieBannerLogicActions {
    loadConfig: () => any
    loadConfigFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    loadConfigSuccess: (
        config: CookieBannerConfigApi,
        payload?: any
    ) => {
        config: CookieBannerConfigApi
        payload?: any
    }
    save: () => {
        value: true
    }
    saveFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    saveSuccess: (
        config: CookieBannerConfigApi,
        payload?: {
            value: true
        }
    ) => {
        config: CookieBannerConfigApi
        payload?: {
            value: true
        }
    }
    setAppearanceValue: (
        key: keyof CookieBannerAppearanceApi,
        value: boolean | string
    ) => {
        key: keyof CookieBannerAppearanceApi
        value: boolean | string
    }
    setAppearanceValues: (values: CookieBannerAppearanceApi) => {
        values: CookieBannerAppearanceApi
    }
    setEnabled: (enabled: boolean) => {
        enabled: boolean
    }
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface cookieBannerLogicMeta {
    __keaTypeGenInternalSelectorTypes: {
        effectiveAppearance: (appearanceDraft: CookieBannerAppearanceApi) => Required<CookieBannerAppearanceApi>
        isDirty: (
            config: CookieBannerConfigApi | null,
            enabledDraft: boolean,
            appearanceDraft: CookieBannerAppearanceApi
        ) => boolean
        activeTheme: (effectiveAppearance: Required<CookieBannerAppearanceApi>) => ThemePreset | null
    }
}

export type cookieBannerLogicType = MakeLogicType<
    cookieBannerLogicValues,
    cookieBannerLogicActions,
    Record<string, any>,
    cookieBannerLogicMeta
>

export const cookieBannerLogic = kea<cookieBannerLogicType>([
    path(['products', 'cookie_banner', 'frontend', 'cookieBannerLogic']),
    connect(() => ({ values: [teamLogic, ['currentTeamId']] })),
    actions({
        setEnabled: (enabled: boolean) => ({ enabled }),
        setAppearanceValue: (key: keyof CookieBannerAppearanceApi, value: string | boolean) => ({ key, value }),
        setAppearanceValues: (values: CookieBannerAppearanceApi) => ({ values }),
        save: true,
    }),
    loaders(({ values }) => ({
        config: [
            null as CookieBannerConfigApi | null,
            {
                loadConfig: async () => {
                    const response = await cookieBannerList(String(values.currentTeamId))
                    return response.results[0] ?? null
                },
                save: async () => {
                    const payload = { enabled: values.enabledDraft, appearance: values.appearanceDraft }
                    const saved = values.config
                        ? await cookieBannerPartialUpdate(String(values.currentTeamId), values.config.id, payload)
                        : await cookieBannerCreate(String(values.currentTeamId), payload)
                    lemonToast.success('Cookie banner saved')
                    return saved
                },
            },
        ],
    })),
    reducers({
        saving: [
            false,
            {
                save: () => true,
                saveSuccess: () => false,
                saveFailure: () => false,
            },
        ],
        enabledDraft: [
            false,
            {
                setEnabled: (_, { enabled }) => enabled,
                loadConfigSuccess: (_, { config }) => config?.enabled ?? false,
                saveSuccess: (_, { config }) => config?.enabled ?? false,
            },
        ],
        appearanceDraft: [
            {} as CookieBannerAppearanceApi,
            {
                setAppearanceValue: (state, { key, value }) => ({ ...state, [key]: value }),
                setAppearanceValues: (state, { values }) => ({ ...state, ...values }),
                loadConfigSuccess: (_, { config }) => config?.appearance ?? {},
                saveSuccess: (_, { config }) => config?.appearance ?? {},
            },
        ],
    }),
    selectors({
        effectiveAppearance: [
            (s) => [s.appearanceDraft],
            (appearanceDraft: CookieBannerAppearanceApi): Required<CookieBannerAppearanceApi> => ({
                ...DEFAULT_APPEARANCE,
                ...appearanceDraft,
            }),
        ],
        isDirty: [
            (s) => [s.config, s.enabledDraft, s.appearanceDraft],
            (
                config: CookieBannerConfigApi | null,
                enabledDraft: boolean,
                appearanceDraft: CookieBannerAppearanceApi
            ): boolean =>
                enabledDraft !== (config?.enabled ?? false) ||
                JSON.stringify(appearanceDraft) !== JSON.stringify(config?.appearance ?? {}),
        ],
        activeTheme: [
            (s) => [s.effectiveAppearance],
            (effectiveAppearance: Required<CookieBannerAppearanceApi>): ThemePreset | null => {
                const themes = Object.keys(THEME_PALETTES) as ThemePreset[]
                return (
                    themes.find((theme) =>
                        Object.entries(THEME_PALETTES[theme]).every(
                            ([key, value]) => effectiveAppearance[key as keyof CookieBannerAppearanceApi] === value
                        )
                    ) ?? null
                )
            },
        ],
    }),
    listeners({
        saveFailure: ({ error }) => {
            lemonToast.error(error || 'Failed to save the cookie banner')
        },
    }),
    afterMount(({ actions }) => {
        actions.loadConfig()
    }),
])
